om/amplify_video/2041932793425620993/vid/avc1/484x270/P_U6ccd4WvB-m8Ff.mp4?tag=21"}, {"bitrate": 832000, "content_type": "video/mp4", "url": "https://video.twimg.com/amplify_video/2041932793425620993/vid/avc1/646x360/TX6rU7tz-hBqCMdJ.mp4?tag=21"}, {"bitrate": 2176000, "content_type": "video/mp4", "url": "https://video.twimg.com/amplify_video/2041932793425620993/vid/avc1/1290x718/5bmJfNMWwGygf1Ch.mp4?tag=21"}]}}], "symbols": [{"indices": [77, 82], "text": "AEHR"}], "timestamps": [], "urls": [], "user_mentions": []}, "extended_entities": {"media": [{"additional_media_info": {"monetizable": true}, "allow_download_status": {"allow_download": true}, "display_url": "pic.x.com/pwhkAzEe0g", "expanded_url": "https://x.com/StockSavvyShay/status/2041932905820434659/video/1", "ext_media_availability": {"status": "Available"}, "id_str": "2041932793425620993", "indices": [281, 304], "media_key": "13_2041932793425620993", "media_results": {"result": {"media_key": "13_2041932793425620993"}}, "media_url_https": "https://pbs.twimg.com/amplify_video_thumb/2041932793425620993/img/797bJKO1Zr1SlEm6.jpg", "original_info": {"focus_rects": [], "height": 718, "width": 1290}, "sizes": {"large": {"h": 718, "resize": "fit", "w": 1290}, "medium": {"h": 668, "resize": "fit", "w": 1200}, "small": {"h": 378, "resize": "fit", "w": 680}, "thumb": {"h": 150, "resize": "crop", "w": 150}}, "type": "video", "url": "https://t.co/pwhkAzEe0g", "video_info": {"aspect_ratio": [645, 359], "duration_millis": 16760, "variants": [{"content_type": "application/x-mpegURL", "url": "https://video.twimg.com/amplify_video/2041932793425620993/pl/LcLTCpi6UsYa4Cbz.m3u8?tag=21&v=e8b"}, {"bitrate": 256000, "content_type": "video/mp4", "url": "https://video.twimg.com/amplify_video/2041932793425620993/vid/avc1/484x270/P_U6ccd4WvB-m8Ff.mp4?tag=21"}, {"bitrate": 832000, "content_type": "video/mp4", "url": "https://video.twimg.com/amplify_video/2041932793425620993/vid/avc1/646x360/TX6rU7tz-hBqCMdJ.mp4?tag=21"}, {"bitrate": 21760